VALUES
  ('optometrist-moex-00644', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '馬竇氏鏡（Maddoxrod）是由那一系列鏡片所組成的？', '["平行平面凹柱面透鏡（parallelplano-concavecylinderlenses）", "平行平面凸柱面透鏡（parallelplano-convexcylinderlenses）", "平行基底朝外稜鏡（parallelbase-outprisms）", "平行基底朝內稜鏡（parallelbase-inprisms）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00645', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關近融像性聚散靈敏度（nearfusionalvergencefacility）測試的目的與方法，下列敘述何者正確？', '["為測試調節帶動聚散的能力，運用反轉正負鏡片，當兩眼遇到正鏡片（pluslens），促使眼睛聚合， 遇到負鏡片（minuslens），促使眼睛開散", "為測試調節帶動聚散的能力，運用反轉正負鏡片，當兩眼遇到正鏡片（pluslens），促使眼睛開散， 遇到負鏡片（minuslens），促使眼睛聚合", "為測試主動融像聚散能力，運用反轉底內與外稜鏡，當兩眼遇到基底向內（base-in）稜鏡，促使眼 睛聚合，遇到基底向外（base-out）稜鏡，促使眼睛開散", "為測試主動融像聚散能力，運用反轉底內與外稜鏡，當兩眼遇到基底向內（base-in）稜鏡，促使眼 睛開散，遇到基底向外（base-out）稜鏡，促使眼睛聚合"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00646', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列何種檢測法不是用在測量水平及垂直的隱斜位量？', '["遮蓋測試合併使用稜鏡", "馬竇氏鏡（Maddoxrod）測量", "托林頓（Thorington）測量", "魏氏四點（Worth4-dot）測量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00647', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關固視偏差（fixationdisparity,FD）的敘述，下列何者錯誤？', '["是雙眼融像情況下，兩眼視線與注視物的落差", "固視偏差（FD），不受眼睛融像續力的補償", "用稜鏡量測的固視偏差（FD）矯正量等於一般的隱斜位量", "內斜固視偏差（esofixationdisparity）是兩眼視線交點落在所見視標平面之前"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00648', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列何者不是在雙眼融像（binocularfusion）的情況下進行檢測？', '["固視偏差（fixationdisparity）", "隱斜位（heterophoria）", "聚散靈敏度（vergencefacility）", "正負相對調節（negativerelativeaccommodation/positiverelativeaccommodation）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00649', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '處理雙眼視覺的異常，如何給予恰當的稜鏡度數，下列何者是不合宜的敘述？', '["關聯性（associated）與非關聯性（disassociated）的隱斜位檢測，都可以提供緩解稜鏡的稜鏡值", "非關聯性檢測，如vonGraefe直接測量的稜鏡值較低，可直接以此稜鏡當緩解稜鏡配鏡", "關聯性檢測，如固視偏差（fixationdisparity），是最合宜配緩解稜鏡的方式", "開散不足（divergenceinsufficiency）有內斜者，適合配戴基底朝外的緩解稜鏡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00650', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '聚合不足（convergenceinsufficiency）與假性聚合不足（pseudoconvergenceinsufficiency）的差異，下 列何者錯誤？', '["兩者都可在看近時表現外隱斜位", "前者AC/A值低，後者AC/A值高", "前者調節幅度正常，後者調節幅度低", "前者的首選治療方式是視覺訓練，後者是近用附加正球鏡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00651', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關垂直平衡失調，下列何者錯誤？', '["可能症狀包括眼周牽拉感、頭痛、視覺疲勞、閱讀時跳行、複視", "檢查方法包括遮蓋試驗、vonGraefe法、馬竇氏鏡檢查", "在高度屈光不正的病人，眼鏡傾斜也可能引發垂直平衡失調", "治療首選方法為視覺訓練，其次為正附加球鏡和稜鏡處方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00652', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關雙眼視功能異常的處理建議，下列何者錯誤？', '["內聚不足首選利用稜鏡矯正", "隱性遠視引起的內隱斜位可利用屈光矯正方式改善", "內隱斜位的眼睛運動訓練會比外隱斜位困難", "補償性外隱斜位可以利用附加負鏡片（minusadd）改善"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00653', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有雙眼視覺相關之症狀者，比較不會出現下列何種固視偏差曲線圖（fixationdisparitycurve）特性？', '["大量的關聯性隱斜位", "較陡的傾斜率（slope）", "較平的傾斜率（slope）", "大量的固視偏差（fixationdisparity）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
